-- Converts every legacy (2024-markdown) monster row to the same
-- structured-JSON columns the classic-SRD import uses — generated by
-- scripts/convert_legacy_monsters.py. Leaves the markdown text columns
-- in place (unused once CombatService.bx's regex fallback is removed,
-- but kept as a historical/audit record).

UPDATE monsters SET actions_json = '[{"name": "Multiattack", "desc": "Multiattack. The aboleth makes two Tentacle attacks and uses either Consume Memories or Dominate Mind if available.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 2, "healAmount": 0}, {"name": "Tentacle", "desc": "Tentacle. Melee Attack Roll: +9, reach 15 ft. Hit: 12 (2d6 + 5) Bludgeoning damage. If the target is a Large or smaller creature, it has the Grappled condition (escape DC 14) from one of four tentacles.", "attackBonus": 9, "damageDice": "2d6", "damageBonus": 5, "damageType": "bludgeoning", "category": "melee", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Consume Memories", "desc": "Consume Memories. Intelligence Saving Throw: DC 16, one creature within 30 feet that is Charmed or Grappled by the aboleth. Failure: 10 (3d6) Psychic damage. <br>\\n&emsp;Success: Half damage. Failure or Success: The aboleth gains the target\'s memories if the target is a Humanoid and is reduced to 0 Hit Points by this action.", "attackBonus": 0, "damageDice": "3d6", "damageBonus": 0, "damageType": "psychic", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "int", "saveAbilityLabel": "Intelligence", "saveDC": 16, "rangeSquares": 6, "multiattackCount": 0, "healAmount": 0}, {"name": "Dominate Mind (2/Day)", "desc": "Dominate Mind (2/Day). Wisdom Saving Throw: DC 16, one creature the aboleth can see within 30 feet. Failure: The target has the Charmed condition until the aboleth dies or is on a different plane of existence from the target. While Charmed, the target acts as an ally to the aboleth and is under its control while within 60 feet of it. In addition, the aboleth and the target can communicate telepathically with each other over any distance. <br>\\n&emsp;The target repeats the save whenever it takes damage as well as after every 24 hours it spends at least 1 mile away from the aboleth, ending the effect on itself on a success.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', special_abilities_json = '[{"name": "Amphibious", "desc": "Amphibious. The aboleth can breathe air and water.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Eldritch Restoration", "desc": "Eldritch Restoration. If destroyed, the aboleth gains a new body in 5d10 days, reviving with all its Hit Points in the Far Realm or another location chosen by the GM.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Legendary Resistance (3/Day, or 4/Day in Lair)", "desc": "Legendary Resistance (3/Day, or 4/Day in Lair). If the aboleth fails a saving throw, it can choose to succeed instead.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Mucus Cloud", "desc": "Mucus Cloud. While underwater, the aboleth is surrounded by mucus. Constitution Saving Throw: DC 14, each creature in a 5-foot Emanation originating from the aboleth at the end of the aboleth\'s turn. Failure: The target is cursed. Until the curse ends, the target\'s skin becomes slimy, the target can breathe air and water, and it can\'t regain Hit Points unless it is underwater. <br>\\n&emsp;While the cursed creature is outside a body of water, the creature takes 6 (1d12) Acid damage at the end of every 10 minutes unless moisture is applied to its skin before those minutes have passed.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Probing Telepathy", "desc": "Probing Telepathy. If a creature the aboleth can see communicates telepathically with the aboleth, the aboleth learns the creature\'s greatest desires.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', legendary_actions_json = '[{"name": "Lash", "desc": "Lash. The aboleth makes one Tentacle attack.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Psychic Drain", "desc": "Psychic Drain. If the aboleth has at least one creature Charmed or Grappled, it uses Consume Memories and regains 5 (1d10) Hit Points.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', reactions_json = NULL WHERE name = 'Aboleth';
