UPDATE monsters SET actions_json = '[{"name": "Bite", "desc": "Bite. Melee Attack Roll: +2, reach 5 ft. Hit: 7 (2d6) Piercing damage. If the target is a Medium or smaller creature, it has the Prone condition. The target dies if it is reduced to 0 Hit Points by this attack. Its body is then absorbed into the mouther, leaving only equipment behind.", "attackBonus": 2, "damageDice": "2d6", "damageBonus": 0, "damageType": "piercing", "category": "melee", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Blinding Spittle (Recharge 5\\u20136)", "desc": "Blinding Spittle (Recharge 5\\u20136). Dexterity Saving Throw: DC 10, each creature in a 10-foot-radius Sphere centered on a point within 30 feet. Failure: 7 (2d6) Radiant damage, and the target has the Blinded condition until the end of the mouther\'s next turn.", "attackBonus": 0, "damageDice": "2d6", "damageBonus": 0, "damageType": "radiant", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "dex", "saveAbilityLabel": "Dexterity", "saveDC": 10, "rangeSquares": 2, "multiattackCount": 0, "healAmount": 0}]', special_abilities_json = '[{"name": "Aberrant Ground", "desc": "Aberrant Ground. The ground in a 10-foot Emanation originating from the mouther is Difficult Terrain.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Gibbering", "desc": "Gibbering. The mouther babbles incoherently while it doesn\'t have the Incapacitated condition. Wisdom Saving Throw: DC 10, any creature that starts its turn within 20 feet of the mouther while it is babbling. Failure: The target rolls 1d8 to determine what it does during the current turn: <br>\\n&emsp;1\\u20134. The target does nothing.<br>\\n&emsp;5\\u20136. The target takes no action or Bonus Action and uses all its movement to move in a random direction.<br>\\n&emsp;7\\u20138. The target makes a melee attack against a randomly determined creature within its reach or does nothing if it can\'t make such an attack.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', legendary_actions_json = NULL, reactions_json = NULL WHERE name = 'Gibbering Mouther';
