UPDATE monsters SET actions_json = '[{"name": "Multiattack", "desc": "Multiattack. The incubus makes two Restless Touch attacks.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 2, "healAmount": 0}, {"name": "Restless Touch", "desc": "Restless Touch. Melee Attack Roll: +7, reach 5 ft. Hit: 15 (3d6 + 5) Psychic damage, and the target is cursed for 24 hours or until the incubus dies. Until the curse ends, the target gains no benefit from finishing Short Rests.", "attackBonus": 7, "damageDice": "3d6", "damageBonus": 5, "damageType": "psychic", "category": "melee", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Spellcasting", "desc": "Spellcasting. The incubus casts one of the following spells, requiring no Material components and using Charisma as the spellcasting ability (spell save DC 15): <br>\\n&emsp;At Will: Disguise Self, Etherealness <br>\\n&emsp;1/Day Each: Dream, Hypnotic Pattern", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', special_abilities_json = '[{"name": "Succubus Form", "desc": "Succubus Form. When the incubus finishes a Long Rest, it can shape-shift into a Succubus, using that stat block instead of this one. Any equipment it is wearing or carrying isn\'t transformed.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Nightmare (Recharge 6)", "desc": "Nightmare (Recharge 6). Wisdom Saving Throw: DC 15, one creature the incubus can see within 60 feet. Failure: If the target has 20 Hit Points or fewer, it has the Unconscious condition for 1 hour, until it takes damage, or until a creature within 5 feet of it takes an action to wake it. Otherwise, the target takes 18 (4d8) Psychic damage.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', legendary_actions_json = NULL, reactions_json = NULL WHERE name = 'Incubus';
