UPDATE monsters SET actions_json = '[{"name": "Multiattack", "desc": "Multiattack. The oni makes two Claw or Nightmare Ray attacks. It can replace one attack with a use of Spellcasting.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 2, "healAmount": 0}, {"name": "Claw", "desc": "Claw. Melee Attack Roll: +7, reach 10 ft. Hit: 10 (1d12 + 4) Slashing damage plus 9 (2d8) Necrotic damage.", "attackBonus": 7, "damageDice": "1d12", "damageBonus": 4, "damageType": "slashing", "category": "melee", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Nightmare Ray", "desc": "Nightmare Ray. Ranged Attack Roll: +5, range 60 ft. Hit: 9 (2d6 + 2) Psychic damage, and the target has the Frightened condition until the start of the oni\'s next turn.", "attackBonus": 5, "damageDice": "2d6", "damageBonus": 2, "damageType": "psychic", "category": "ranged", "normalRange": 12, "longRange": 12, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Shape-Shift", "desc": "Shape-Shift. The oni shape-shifts into a Small or Medium Humanoid or a Large Giant, or it returns to its true form. Other than its size, its game statistics are the same in each form. Any equipment it is wearing or carrying isn\'t transformed.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Spellcasting", "desc": "Spellcasting. The oni casts one of the following spells, requiring no Material components and using Charisma as the spellcasting ability (spell save DC 13): <br>\\n&emsp;1/Day Each: Charm Person (level 2 version), Darkness, Gaseous Form, Sleep", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', special_abilities_json = '[{"name": "Regeneration", "desc": "Regeneration. The oni regains 10 Hit Points at the start of each of its turns if it has at least 1 Hit Point.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 10}, {"name": "Invisibility", "desc": "Invisibility. The oni casts Invisibility on itself, requiring no spell components and using the same spellcasting ability as Spellcasting.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', legendary_actions_json = NULL, reactions_json = NULL WHERE name = 'Oni';
UPDATE monsters SET actions_json = '[{"name": "Multiattack", "desc": "Multiattack. The otyugh makes one Bite attack and two Tentacle attacks.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 1, "healAmount": 0}, {"name": "Bite", "desc": "Bite. Melee Attack Roll: +6, reach 5 ft. Hit: 12 (2d8 + 3) Piercing damage, and the target has the Poisoned condition. Whenever the Poisoned target finishes a Long Rest, it is subjected to the following effect. Constitution Saving Throw: DC 15. Failure: The target\'s Hit Point maximum decreases by 5 (1d10) and doesn\'t return to normal until the Poisoned condition ends on the target. Success: The Poisoned condition ends.", "attackBonus": 6, "damageDice": "2d8", "damageBonus": 3, "damageType": "piercing", "category": "melee", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Tentacle", "desc": "Tentacle. Melee Attack Roll: +6, reach 10 ft. Hit: 12 (2d8 + 3) Piercing damage. If the target is a Medium or smaller creature, it has the Grappled condition (escape DC 13) from one of two tentacles.", "attackBonus": 6, "damageDice": "2d8", "damageBonus": 3, "damageType": "piercing", "category": "melee", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Tentacle Slam", "desc": "Tentacle Slam. Constitution Saving Throw: DC 14, each creature Grappled by the otyugh. Failure: 16 (3d8 + 3) Bludgeoning damage, and the target has the Stunned condition until the start of the otyugh\'s next turn. Success: Half damage only.", "attackBonus": 0, "damageDice": "3d8", "damageBonus": 3, "damageType": "bludgeoning", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "con", "saveAbilityLabel": "Constitution", "saveDC": 14, "rangeSquares": 6, "multiattackCount": 0, "healAmount": 0}]', special_abilities_json = NULL, legendary_actions_json = NULL, reactions_json = NULL WHERE name = 'Otyugh';
