healAmount": 0}]', special_abilities_json = '[{"name": "Magic Resistance", "desc": "Magic Resistance. The quasit has Advantage on saving throws against spells and other magical effects.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', legendary_actions_json = NULL, reactions_json = NULL WHERE name = 'Quasit';
UPDATE monsters SET actions_json = '[{"name": "Multiattack", "desc": "Multiattack. The rakshasa makes three Cursed Touch attacks.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 3, "healAmount": 0}, {"name": "Cursed Touch", "desc": "Cursed Touch. Melee Attack Roll: +10, reach 5 ft. Hit: 12 (2d6 + 5) Slashing damage plus 19 (3d12) Necrotic damage. If the target is a creature, it is cursed. While cursed, the target gains no benefit from finishing a Short or Long Rest.", "attackBonus": 10, "damageDice": "2d6", "damageBonus": 5, "damageType": "slashing", "category": "melee", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Baleful Command (Recharge 5\\u20136)", "desc": "Baleful Command (Recharge 5\\u20136). Wisdom Saving Throw: DC 18, each enemy in a 30-foot Emanation originating from the rakshasa. Failure: 28 (8d6) Psychic damage, and the target has the Frightened and Incapacitated conditions until the start of the rakshasa\'s next turn.", "attackBonus": 0, "damageDice": "8d6", "damageBonus": 0, "damageType": "psychic", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "wis", "saveAbilityLabel": "Wisdom", "saveDC": 18, "rangeSquares": 6, "multiattackCount": 0, "healAmount": 0}, {"name": "Spellcasting", "desc": "Spellcasting. The rakshasa casts one of the following spells, requiring no Material components and using Charisma as the spellcasting ability (spell save DC 18): <br>\\n&emsp;At Will: Detect Magic, Detect Thoughts, Disguise Self, Mage Hand, Minor Illusion <br>\\n&emsp;1/Day Each: Fly, Invisibility, Major Image, Plane Shift", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', special_abilities_json = '[{"name": "Greater Magic Resistance", "desc": "Greater Magic Resistance. The rakshasa automatically succeeds on saving throws against spells and other magical effects, and the attack rolls of spells automatically miss it. Without the rakshasa\'s permission, no spell can observe the rakshasa remotely or detect its thoughts, creature type, or alignment.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Fiendish Restoration", "desc": "Fiendish Restoration. If the rakshasa dies outside the Nine Hells, its body turns to ichor, and it gains a new body instantly, reviving with all its Hit Points somewhere in the Nine Hells.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', legendary_actions_json = NULL, reactions_json = NULL WHERE name = 'Rakshasa';
