UPDATE monsters SET actions_json = '[{"name": "Multiattack", "desc": "Multiattack. The roper makes two Tentacle attacks, uses Reel, and makes two Bite attacks.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 2, "healAmount": 0}, {"name": "Bite", "desc": "Bite. Melee Attack Roll: +7, reach 5 ft. Hit: 17 (3d8 + 4) Piercing damage.", "attackBonus": 7, "damageDice": "3d8", "damageBonus": 4, "damageType": "piercing", "category": "melee", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Tentacle", "desc": "Tentacle. Melee Attack Roll: +7, reach 60 ft. Hit: The target has the Grappled condition (escape DC 14) from one of six tentacles, and the target has the Poisoned condition until the grapple ends. <br>\\n&emsp;The tentacle can be damaged, freeing a creature it has Grappled when destroyed (AC 20, HP 10, Immunity to Poison and Psychic damage). Damaging the tentacle deals no damage to the roper, and a destroyed tentacle regrows at the start of the roper\'s next turn.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Reel", "desc": "Reel. The roper pulls each creature Grappled by it up to 30 feet straight toward it.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', special_abilities_json = '[{"name": "Spider Climb", "desc": "Spider Climb. The roper can climb difficult surfaces, including along ceilings, without needing to make an ability check.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', legendary_actions_json = NULL, reactions_json = NULL WHERE name = 'Roper';
UPDATE monsters SET actions_json = '[{"name": "Multiattack", "desc": "Multiattack. The rust monster makes one Bite attack and uses Antennae twice.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 1, "healAmount": 0}, {"name": "Bite", "desc": "Bite. Melee Attack Roll: +3, reach 5 ft. Hit: 5 (1d8 + 1) Piercing damage.", "attackBonus": 3, "damageDice": "1d8", "damageBonus": 1, "damageType": "piercing", "category": "melee", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Antennae", "desc": "Antennae. The rust monster targets one nonmagical metal object\\u2014armor or a weapon\\u2014worn or carried by a creature within 5 feet of itself. Dexterity Saving Throw: DC 11, the creature with the object. Failure: The object takes a \\u22121 penalty to the AC it offers (armor) or to its attack rolls (weapon). Armor is destroyed if the penalty reduces its AC to 10, and a weapon is destroyed if its penalty reaches \\u22125. The penalty can be removed by casting the Mending spell on the armor or weapon.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Destroy Metal", "desc": "Destroy Metal. The rust monster touches a nonmagical metal object within 5 feet of itself that isn\'t being worn or carried. The touch destroys a 1-foot Cube of the object.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', special_abilities_json = '[{"name": "Iron Scent", "desc": "Iron Scent. The rust monster can pinpoint the location of ferrous metal within 30 feet of itself.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', legendary_actions_json = NULL, reactions_json = '[{"name": "Reflexive Antennae", "desc": "Reflexive Antennae. Trigger: An attack roll hits the rust monster. Response: The rust monster uses Antennae.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]' WHERE name = 'Rust Monster';
