Aquatic Charge. The sahuagin swims up to its Swim Speed straight toward an enemy it can see.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', legendary_actions_json = NULL, reactions_json = NULL WHERE name = 'Sahuagin Warrior';
UPDATE monsters SET actions_json = '[{"name": "Multiattack", "desc": "Multiattack. The salamander makes two Flame Spear attacks. It can replace one attack with a use of Constrict.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 2, "healAmount": 0}, {"name": "Flame Spear", "desc": "Flame Spear. Melee or Ranged Attack Roll: +7, reach 5 ft. or range 20/60 ft. Hit: 13 (2d8 + 4) Piercing damage plus 7 (2d6) Fire damage. Hit or Miss: The spear magically returns to the salamander\'s hand immediately after a ranged attack.", "attackBonus": 7, "damageDice": "2d8", "damageBonus": 4, "damageType": "piercing", "category": "melee", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Constrict", "desc": "Constrict. Strength Saving Throw: DC 15, one Large or smaller creature the salamander can see within 10 feet. Failure: 11 (2d6 + 4) Bludgeoning damage plus 7 (2d6) Fire damage. The target has the Grappled condition (escape DC 14), and it has the Restrained condition until the grapple ends.", "attackBonus": 0, "damageDice": "2d6", "damageBonus": 4, "damageType": "bludgeoning", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "str", "saveAbilityLabel": "Strength", "saveDC": 15, "rangeSquares": 2, "multiattackCount": 0, "healAmount": 0}]', special_abilities_json = '[{"name": "Fire Aura", "desc": "Fire Aura. At the end of each of the salamander\'s turns, each creature of the salamander\'s choice in a 5-foot Emanation originating from the salamander takes 7 (2d6) Fire damage.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', legendary_actions_json = NULL, reactions_json = NULL WHERE name = 'Salamander';
