UPDATE monsters SET actions_json = '[{"name": "Multiattack", "desc": "Multiattack. The unicorn makes one Hooves attack and one Radiant Horn attack.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 1, "healAmount": 0}, {"name": "Hooves", "desc": "Hooves. Melee Attack Roll: +7, reach 5 ft. Hit: 11 (2d6 + 4) Bludgeoning damage.", "attackBonus": 7, "damageDice": "2d6", "damageBonus": 4, "damageType": "bludgeoning", "category": "melee", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Radiant Horn", "desc": "Radiant Horn. Melee Attack Roll: +7, reach 5 ft. Hit: 9 (1d10 + 4) Radiant damage.", "attackBonus": 7, "damageDice": "1d10", "damageBonus": 4, "damageType": "radiant", "category": "melee", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Spellcasting", "desc": "Spellcasting. The unicorn casts one of the following spells, requiring no spell components and using Charisma as the spellcasting ability (spell save DC 14): <br>\\n&emsp;At Will: Detect Evil and Good, Druidcraft <br>\\n&emsp;1/Day Each: Calm Emotions, Dispel Evil and Good, Entangle, Pass without Trace, Word of Recall", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', special_abilities_json = '[{"name": "Legendary Resistance (3/Day)", "desc": "Legendary Resistance (3/Day). If the unicorn fails a saving throw, it can choose to succeed instead.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Magic Resistance", "desc": "Magic Resistance. The unicorn has Advantage on saving throws against spells and other magical effects.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Unicorn\'s Blessing (3/Day)", "desc": "Unicorn\'s Blessing (3/Day). The unicorn touches another creature with its horn and casts Cure Wounds or Lesser Restoration on that creature, using the same spellcasting ability as Spellcasting.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', legendary_actions_json = '[{"name": "Charging Horn", "desc": "Charging Horn. The unicorn moves up to half its Speed without provoking Opportunity Attacks, and it makes one Radiant Horn attack.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Shimmering Shield", "desc": "Shimmering Shield. The unicorn targets itself or one creature it can see within 60 feet of itself. The target gains 10 (3d6) Temporary Hit Points, and its AC increases by 2 until the end of the unicorn\'s next turn. <br>\\n&emsp;The unicorn can\'t take this action again until the start of its next turn.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', reactions_json = NULL WHERE name = 'Unicorn';
UPDATE monsters SET actions_json = '[{"name": "Multiattack (Vampire Form Only)", "desc": "Multiattack (Vampire Form Only). The vampire makes two Grave Strike attacks and uses Bite.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Grave Strike (Vampire Form Only)", "desc": "Grave Strike (Vampire Form Only). Melee Attack Roll: +9, reach 5 ft. Hit: 8 (1d8 + 4) Bludgeoning damage plus 7 (2d6) Necrotic damage. If the target is a Large or smaller creature, it has the Grappled condition (escape DC 14) from one of two hands.", "attackBonus": 9, "damageDice": "1d8", "damageBonus": 4, "damageType": "bludgeoning", "category": "melee", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Bite (Bat or Vampire Form Only)", "desc": "Bite (Bat or Vampire Form Only). Constitution Saving Throw: DC 17, one creature within 5 feet that is willing or that has the Grappled, Incapacitated, or Restrained condition. Failure: 6 (1d4 + 4) Piercing damage plus 13 (3d8) Necrotic damage. The target\'s Hit Point maximum decreases by an amount equal to the Necrotic damage taken, and the vampire regains Hit Points equal to that amount. A Humanoid reduced to 0 Hit Points by this damage and then buried rises the following sunset as a Vampire Spawn under the vampire\'s control.", "attackBonus": 0, "damageDice": "1d4", "damageBonus": 4, "damageType": "piercing", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "con", "saveAbilityLabel": "Constitution", "saveDC": 17, "rangeSquares": 1, "multiattackCount": 0, "healAmount": 0}]', special_abilities_json = '[{"name": "Legendary Resistance (3/Day, or 4/Day in Lair)", "desc": "Legendary Resistance (3/Day, or 4/Day in Lair). If the vampire fails a saving throw, it can choose to succeed instead.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Misty Escape", "desc": "Misty Escape. If the vampire drops to 0 Hit Points outside its resting place, the vampire uses Shape-Shift to become mist (no action required). If it can\'t use Shape-Shift, it is destroyed. <br>\\n&emsp;While it has 0 Hit Points in mist form, it can\'t return to its vampire form, and it must reach its resting place within 2 hours or be destroyed. Once in its resting place, it returns to its vampire form and has the Paralyzed condition until it regains any Hit Points, and it regains 1 Hit Point after spending 1 hour there.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Spider Climb", "desc": "Spider Climb. The vampire can climb difficult surfaces, including along ceilings, without needing to make an ability check.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Vampire Weakness", "desc": "Vampire Weakness. The vampire has these weaknesses:", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Forbiddance", "desc": "Forbiddance. The vampire can\'t enter a residence without an invitation from an occupant.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Running Water", "desc": "Running Water. The vampire takes 20 Acid damage if it ends its turn in running water.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Stake to the Heart", "desc": "Stake to the Heart. If a weapon that deals Piercing damage is driven into the vampire\'s heart while the vampire has the Incapacitated condition in its resting place, the vampire has the Paralyzed condition until the weapon is removed.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Sunlight", "desc": "Sunlight. The vampire takes 20 Radiant damage if it starts its turn in sunlight. While in sunlight, it has Disadvantage on attack rolls and ability checks.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Charm (Recharge 5\\u20136)", "desc": "Charm (Recharge 5\\u20136). The vampire casts Charm Person, requiring no spell components and using Charisma as the spellcasting ability (spell save DC 17), and the duration is 24 hours. The Charmed target is a willing recipient of the vampire\'s Bite, the damage of which doesn\'t end the spell. When the spell ends, the target is unaware it was Charmed by the vampire.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Shape-Shift", "desc": "Shape-Shift. If the vampire isn\'t in sunlight or running water, it shape-shifts into a Tiny bat (Speed 5 ft., Fly Speed 30 ft.) or a Medium cloud of mist (Speed 5 ft., Fly Speed 20 ft. [hover]), or it returns to its vampire form. Anything it is wearing transforms with it. <br>\\n&emsp;While in bat form, the vampire can\'t speak. Its game statistics, other than its size and Speed, are unchanged. <br>\\n&emsp;While in mist form, the vampire can\'t take any actions, speak, or manipulate objects. It is weightless and can enter an enemy\'s space and stop there. If air can pass through a space, the mist can do so, but it can\'t pass through liquid. It has Resistance to all damage, except the damage it takes from sunlight.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', legendary_actions_json = '[{"name": "Beguile", "desc": "Beguile. The vampire casts Command, requiring no spell components and using Charisma as the spellcasting ability (spell save DC 17). The vampire can\'t take this action again until the start of its next turn.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Deathless Strike", "desc": "Deathless Strike. The vampire moves up to half its Speed, and it makes one Grave Strike attack.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', reactions_json = NULL WHERE name = 'Vampire';
