UPDATE monsters SET actions_json = '[{"name": "Multiattack", "desc": "Multiattack. The elemental makes two Slam attacks.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 2, "healAmount": 0}, {"name": "Slam", "desc": "Slam. Melee Attack Roll: +7, reach 5 ft. Hit: 13 (2d8 + 4) Bludgeoning damage. If the target is a Medium or smaller creature, it has the Prone condition.", "attackBonus": 7, "damageDice": "2d8", "damageBonus": 4, "damageType": "bludgeoning", "category": "melee", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Whelm (Recharge 4\\u20136)", "desc": "Whelm (Recharge 4\\u20136). Strength Saving Throw: DC 15, each creature in the elemental\'s space. Failure: 22 (4d8 + 4) Bludgeoning damage. If the target is a Large or smaller creature, it has the Grappled condition (escape DC 14). Until the grapple ends, the target has the Restrained condition, is suffocating unless it can breathe water, and takes 9 (2d8) Bludgeoning damage at the start of each of the elemental\'s turns. The elemental can grapple one Large creature or up to two Medium or smaller creatures at a time with Whelm. As an action, a creature within 5 feet of the elemental can pull a creature out of it by succeeding on a DC 14 Strength (Athletics) check. Success: Half damage only.", "attackBonus": 0, "damageDice": "4d8", "damageBonus": 4, "damageType": "bludgeoning", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "str", "saveAbilityLabel": "Strength", "saveDC": 15, "rangeSquares": 6, "multiattackCount": 0, "healAmount": 0}]', special_abilities_json = '[{"name": "Freeze", "desc": "Freeze. If the elemental takes Cold damage, its Speed decreases by 20 feet until the end of its next turn.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Water Form", "desc": "Water Form. The elemental can enter an enemy\'s space and stop there. It can move through a space as narrow as 1 inch without expending extra movement to do so.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', legendary_actions_json = NULL, reactions_json = NULL WHERE name = 'Water Elemental';
